targets.expr:
sum by (redis_host, environment, redis_cluster) (
  redis_connected_clients{job="redis-exporters", redis_cluster=~"$cluster", environment=~"$env", redis_host=~"$host", exporter_port=~"$xport"}
)

topk(
10,
sum by (cmd) (
  rate(redis_commands_total{
    job="redis-exporters",
    redis_cluster=~"$cluster",
    environment=~"$env"
  }[5m])
)
)

topk(
  10,
  1000 *
  (
    sum by (cmd) (
      rate(redis_commands_duration_seconds_total{
        job="redis-exporters",
        redis_cluster=~"$cluster",
        environment=~"$env",
        redis_host=~"$host",
        exporter_port=~"$xport"
      }[5m])
    )
    /
    sum by (cmd) (
      rate(redis_commands_total{
        job="redis-exporters",
        redis_cluster=~"$cluster",
        environment=~"$env",
        redis_host=~"$host",
        exporter_port=~"$xport"
      }[5m])
    )
  )
)

sum by (db) (
redis_db_keys{
  job="redis-exporters",
  redis_cluster=~"$cluster",
  environment=~"$env"
}
)

100 *
sum(increase(redis_keyspace_hits_total{
  job="redis-exporters",
  redis_cluster=~"$cluster",
  environment=~"$env"
}[$__range]))
/
(
  sum(increase(redis_keyspace_hits_total{
    job="redis-exporters",
    redis_cluster=~"$cluster",
    environment=~"$env"
  }[$__range]))
+
  sum(increase(redis_keyspace_misses_total{
    job="redis-exporters",
    redis_cluster=~"$cluster",
    environment=~"$env"
  }[$__range]))
)

sum by (redis_host) (
  redis_db_keys{
    job="redis-exporters",
    redis_cluster=~"$cluster",
    environment=~"$env"
  }
)

(
  max by (redis_cluster, environment) (
    sum by (redis_host, redis_cluster, environment) (
      redis_db_keys{job="redis-exporters", redis_cluster=~"$cluster", environment=~"$env"}
    )
  )
)
/
(
  avg by (redis_cluster, environment) (
    sum by (redis_host, redis_cluster, environment) (
      redis_db_keys{job="redis-exporters", redis_cluster=~"$cluster", environment=~"$env"}
    )
  )
)
